import{_ as s,c as a,o as l,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"列出可用技能: 查询与管理 | opencode-agent-skills","description":"学习列出可用技能的方法。掌握命名空间、模糊匹配和搜索过滤，快速定位所需技能，理解技能发现优先级，提升开发效率。","frontmatter":{"title":"列出可用技能: 查询与管理 | opencode-agent-skills","sidebarTitle":"列出技能","subtitle":"列出可用技能: 查询与管理","description":"学习列出可用技能的方法。掌握命名空间、模糊匹配和搜索过滤，快速定位所需技能，理解技能发现优先级，提升开发效率。","tags":["Skill Management","Tool Usage","Namespace"],"prerequisite":["start-installation"],"order":2},"headers":[],"relativePath":"joshuadavidthomas/opencode-agent-skills/platforms/listing-available-skills/index.md","filePath":"joshuadavidthomas/opencode-agent-skills/platforms/listing-available-skills/index.md"}'),t={name:"joshuadavidthomas/opencode-agent-skills/platforms/listing-available-skills/index.md"};function n(o,e,r,p,c,d){return l(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="query-and-list-available-skills" tabindex="-1">Query and List Available Skills <a class="header-anchor" href="#query-and-list-available-skills" aria-label="Permalink to &quot;Query and List Available Skills&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Use the <code>get_available_skills</code> tool to list all available skills</li><li>Filter specific skills through search queries</li><li>Use namespaces (like <code>project:skill-name</code>) to precisely locate skills</li><li>Identify skill sources and lists of executable scripts</li></ul><h2 id="your-current-challenge" tabindex="-1">Your Current Challenge <a class="header-anchor" href="#your-current-challenge" aria-label="Permalink to &quot;Your Current Challenge&quot;">​</a></h2><p>You want to use a skill but can&#39;t recall its exact name. Perhaps you know it&#39;s a skill in your project, but you&#39;re not sure which discovery path it&#39;s under. Or you just want to quickly browse what skills are available in your current project.</p><h2 id="when-to-use-this" tabindex="-1">When to Use This <a class="header-anchor" href="#when-to-use-this" aria-label="Permalink to &quot;When to Use This&quot;">​</a></h2><ul><li><strong>Explore new projects</strong>: When joining a new project, quickly understand what skills are available</li><li><strong>Uncertain skill names</strong>: You only remember part of a skill&#39;s name or description and need fuzzy matching</li><li><strong>Multiple namespace conflicts</strong>: Project-level and user-level skills have the same name, and you need to explicitly specify which one to use</li><li><strong>Find scripts</strong>: You want to know what executable automation scripts are available in a skill directory</li></ul><h2 id="core-concept" tabindex="-1">Core Concept <a class="header-anchor" href="#core-concept" aria-label="Permalink to &quot;Core Concept&quot;">​</a></h2><p>The <code>get_available_skills</code> tool helps you view all skills available in the current session. The plugin automatically scans skills from 6 discovery paths:</p><div class="info custom-block"><p class="custom-block-title">Skill Discovery Priority</p><ol><li><code>.opencode/skills/</code> (Project-level OpenCode)</li><li><code>.claude/skills/</code> (Project-level Claude)</li><li><code>~/.config/opencode/skills/</code> (User-level OpenCode)</li><li><code>~/.claude/skills/</code> (User-level Claude)</li><li><code>~/.claude/plugins/cache/</code> (Plugin cache)</li><li><code>~/.claude/plugins/marketplaces/</code> (Installed plugins)</li></ol></div><p>Skills with the same name retain only the first one based on priority; subsequent ones are ignored.</p><p>The information returned by the tool includes:</p><ul><li><strong>Skill name</strong></li><li><strong>Source label</strong> (project, user, claude-project, etc.)</li><li><strong>Description</strong></li><li><strong>List of executable scripts</strong> (if any)</li></ul><div class="tip custom-block"><p class="custom-block-title">Namespace Syntax</p><p>You can explicitly specify the source using the <code>namespace:skill-name</code> format:</p><ul><li><code>project:my-skill</code> - Use project-level OpenCode skill (<code>.opencode/skills/</code>)</li><li><code>claude-project:my-skill</code> - Use project-level Claude skill (<code>.claude/skills/</code>)</li><li><code>user:my-skill</code> - Use user-level OpenCode skill (<code>~/.config/opencode/skills/</code>)</li><li><code>claude-user:my-skill</code> - Use user-level Claude skill (<code>~/.claude/skills/</code>)</li><li><code>claude-plugins:my-skill</code> - Use skills from Claude plugins</li></ul></div><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-list-all-available-skills" tabindex="-1">Step 1: List All Available Skills <a class="header-anchor" href="#step-1-list-all-available-skills" aria-label="Permalink to &quot;Step 1: List All Available Skills&quot;">​</a></h3><p>In OpenCode, directly ask the AI to list skills:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User input:</span></span>
<span class="line"><span>List all available skills</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System response:</span></span>
<span class="line"><span>skill-helper (project)</span></span>
<span class="line"><span>  Git operations and branch management assistant [scripts: tools/branch.sh, tools/commit.sh]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>test-helper (user)</span></span>
<span class="line"><span>  Unit testing and coverage analysis tool</span></span>
<span class="line"><span></span></span>
<span class="line"><span>docker-helper (project)</span></span>
<span class="line"><span>  Docker containerization and deployment guide [scripts: build.sh, deploy.sh]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>claude-code-superpowers (claude-plugins)</span></span>
<span class="line"><span>  Complete software development workflow</span></span></code></pre></div><p><strong>What you should see</strong>: A list of skills, each showing name, source label, description, and script list.</p><h3 id="step-2-filter-with-search-query" tabindex="-1">Step 2: Filter with Search Query <a class="header-anchor" href="#step-2-filter-with-search-query" aria-label="Permalink to &quot;Step 2: Filter with Search Query&quot;">​</a></h3><p>If you only remember part of a skill&#39;s name:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User input:</span></span>
<span class="line"><span>Find skills containing &quot;docker&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System response:</span></span>
<span class="line"><span>docker-helper (project)</span></span>
<span class="line"><span>  Docker containerization and deployment guide [scripts: build.sh, deploy.sh]</span></span></code></pre></div><p>Search matches keywords in skill names and descriptions, supporting the <code>*</code> wildcard:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User input:</span></span>
<span class="line"><span>Find skills starting with &quot;test&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System response:</span></span>
<span class="line"><span>test-helper (user)</span></span>
<span class="line"><span>  Unit testing and coverage analysis tool</span></span></code></pre></div><p><strong>What you should see</strong>: Only skills matching the query criteria are displayed.</p><h3 id="step-3-experience-fuzzy-match-suggestions" tabindex="-1">Step 3: Experience Fuzzy Match Suggestions <a class="header-anchor" href="#step-3-experience-fuzzy-match-suggestions" aria-label="Permalink to &quot;Step 3: Experience Fuzzy Match Suggestions&quot;">​</a></h3><p>If you enter an incorrect skill name:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User input:</span></span>
<span class="line"><span>I want to use docker-asistant</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System response:</span></span>
<span class="line"><span>No skills found matching &quot;docker-asistant&quot;. Did you mean &quot;docker-helper&quot;?</span></span></code></pre></div><p>The plugin calculates similarity based on Levenshtein distance and automatically suggests the closest skill name.</p><p><strong>What you should see</strong>: An error message and the correct skill suggestion.</p><h3 id="step-4-use-namespaces-for-precise-location" tabindex="-1">Step 4: Use Namespaces for Precise Location <a class="header-anchor" href="#step-4-use-namespaces-for-precise-location" aria-label="Permalink to &quot;Step 4: Use Namespaces for Precise Location&quot;">​</a></h3><p>Assume both project-level and user-level have a skill named <code>build-helper</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User input:</span></span>
<span class="line"><span>List detailed information for build-helper</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System response:</span></span>
<span class="line"><span>build-helper (project)</span></span>
<span class="line"><span>  Project-specific build configuration and compilation optimization [scripts: build.sh, optimize.sh]</span></span></code></pre></div><p>If the user wants the user-level skill:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User input:</span></span>
<span class="line"><span>Use user:build-helper</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System response:</span></span>
<span class="line"><span>build-helper (user)</span></span>
<span class="line"><span>  General build toolchain and continuous integration configuration [scripts: ci.sh, test.sh]</span></span></code></pre></div><p><strong>What you should see</strong>: Through namespace prefixes, you can access skills with the same name from different sources.</p><h3 id="step-5-check-executable-scripts" tabindex="-1">Step 5: Check Executable Scripts <a class="header-anchor" href="#step-5-check-executable-scripts" aria-label="Permalink to &quot;Step 5: Check Executable Scripts&quot;">​</a></h3><p>View what scripts are in a skill directory:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User input:</span></span>
<span class="line"><span>What scripts does docker-helper have?</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System response:</span></span>
<span class="line"><span>docker-helper (project)</span></span>
<span class="line"><span>  Docker containerization and deployment guide [scripts: build.sh, deploy.sh]</span></span></code></pre></div><p>Scripts are displayed in brackets after the skill information, separated by commas. You can execute these scripts using the <code>run_skill_script</code> tool.</p><p><strong>What you should see</strong>: The skill name followed by a list in the format <code>[scripts: script-path1, script-path2, ...]</code>.</p><h2 id="checklist-✅" tabindex="-1">Checklist ✅ <a class="header-anchor" href="#checklist-✅" aria-label="Permalink to &quot;Checklist ✅&quot;">​</a></h2><ul><li>[ ] Can you list all available skills?</li><li>[ ] Can you filter specific skills using search queries?</li><li>[ ] Do you understand the meaning of skill source labels (project, user, claude-project, etc.)?</li><li>[ ] Can you explain the purpose and syntax of skill namespaces?</li><li>[ ] Can you identify the list of executable scripts from skill information?</li></ul><h2 id="common-pitfalls" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h2><h3 id="pitfall-1-override-of-same-name-skills" tabindex="-1">Pitfall 1: Override of Same-Name Skills <a class="header-anchor" href="#pitfall-1-override-of-same-name-skills" aria-label="Permalink to &quot;Pitfall 1: Override of Same-Name Skills&quot;">​</a></h3><p>If project-level and user-level have skills with the same name, you might be confused why the loaded skill isn&#39;t the one you expected.</p><p><strong>Cause</strong>: Skills are discovered by priority, with project-level taking precedence over user-level, and only the first same-name skill is retained.</p><p><strong>Solution</strong>: Use namespaces to explicitly specify, such as <code>user:my-skill</code> instead of <code>my-skill</code>.</p><h3 id="pitfall-2-search-case-sensitivity" tabindex="-1">Pitfall 2: Search Case Sensitivity <a class="header-anchor" href="#pitfall-2-search-case-sensitivity" aria-label="Permalink to &quot;Pitfall 2: Search Case Sensitivity&quot;">​</a></h3><p>Search queries use regular expressions but with the <code>i</code> flag set, so they are case-insensitive.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># These searches are equivalent</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;docker&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;DOCKER&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;Docker&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h3 id="pitfall-3-escaping-wildcards" tabindex="-1">Pitfall 3: Escaping Wildcards <a class="header-anchor" href="#pitfall-3-escaping-wildcards" aria-label="Permalink to &quot;Pitfall 3: Escaping Wildcards&quot;">​</a></h3><p>The <code>*</code> in searches is automatically converted to <code>.*</code> regular expression, so manual escaping is not needed:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Search for skills starting with &quot;test&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;test*&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Equivalent to regular expression /test.*/i</span></span></code></pre></div><h2 id="lesson-summary" tabindex="-1">Lesson Summary <a class="header-anchor" href="#lesson-summary" aria-label="Permalink to &quot;Lesson Summary&quot;">​</a></h2><p><code>get_available_skills</code> is a tool for exploring the skills ecosystem, supporting:</p><ul><li><strong>List all skills</strong>: Call without parameters</li><li><strong>Search filtering</strong>: Match names and descriptions through the <code>query</code> parameter</li><li><strong>Namespaces</strong>: Precisely locate using <code>namespace:skill-name</code></li><li><strong>Fuzzy match suggestions</strong>: Automatically suggest correct names on spelling errors</li><li><strong>Script listing</strong>: Display executable automation scripts</li></ul><p>The plugin automatically injects the skill list at the start of a session, so you typically don&#39;t need to manually call this tool. However, it&#39;s useful in these scenarios:</p><ul><li>Want to quickly browse available skills</li><li>Can&#39;t remember the exact skill name</li><li>Need to distinguish between skills with the same name from different sources</li><li>Want to view the script list for a specific skill</li></ul><h2 id="preview-of-next-lesson" tabindex="-1">Preview of Next Lesson <a class="header-anchor" href="#preview-of-next-lesson" aria-label="Permalink to &quot;Preview of Next Lesson&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../loading-skills-into-context/">Loading Skills into Session Context</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>Use the use_skill tool to load skills into the current session</li><li>Understand how skill content is injected into the context in XML format</li><li>Master the Synthetic Message Injection mechanism</li><li>Learn how skills remain available after session compression</li></ul></blockquote><hr><h2 id="appendix-source-reference" tabindex="-1">Appendix: Source Reference <a class="header-anchor" href="#appendix-source-reference" aria-label="Permalink to &quot;Appendix: Source Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Last updated: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Function</th><th>File Path</th><th>Line Range</th></tr></thead><tbody><tr><td>GetAvailableSkills tool definition</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L29-L72" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>29-72</td></tr><tr><td>discoverAllSkills function</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L240-L263" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>240-263</td></tr><tr><td>resolveSkill function</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L269-L283" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>269-283</td></tr><tr><td>findClosestMatch function</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/utils.ts#L88-L125" target="_blank" rel="noreferrer"><code>src/utils.ts</code></a></td><td>88-125</td></tr></tbody></table><p><strong>Key Types</strong>:</p><ul><li><code>SkillLabel = &quot;project&quot; | &quot;user&quot; | &quot;claude-project&quot; | &quot;claude-user&quot; | &quot;claude-plugins&quot;</code>: Skill source label enum</li></ul><p><strong>Key Constants</strong>:</p><ul><li>Fuzzy match threshold: <code>0.4</code> (<code>utils.ts:124</code>) - Similarity below this value doesn&#39;t return suggestions</li></ul><p><strong>Key Functions</strong>:</p><ul><li><code>GetAvailableSkills()</code>: Returns a formatted skill list, supporting query filtering and fuzzy match suggestions</li><li><code>resolveSkill(skillName: string, skillsByName: Map&lt;string, Skill&gt;)</code>: Supports skill resolution in <code>namespace:skill-name</code> format</li><li><code>findClosestMatch(input: string, candidates: string[])</code>: Calculates best match based on multiple matching strategies (prefix, contains, edit distance)</li></ul><p><strong>Business Rules</strong>:</p><ul><li>Same-name skills are deduplicated by discovery order, keeping only the first one (<code>skills.ts:258</code>)</li><li>Search queries support wildcard <code>*</code>, automatically converted to regular expressions (<code>tools.ts:43</code>)</li><li>Fuzzy match suggestions only trigger when there&#39;s a query parameter and no results (<code>tools.ts:49-57</code>)</li></ul></details>`,64)])])}const k=s(t,[["render",n]]);export{u as __pageData,k as default};
